import Link from 'next/link'

export interface FormCardProps {
	slug: string
	name: string
	description: string | null
	locale: string
}

export function FormCard({ slug, name, description, locale }: FormCardProps) {
	return (
		<Link
			href={`/${locale}/forms/${slug}`}
			className="card bg-base-100 border border-base-200 shadow-sm hover:shadow-md transition-shadow"
		>
			<div className="card-body">
				<h2 className="card-title">{name}</h2>
				{description && (
					<p className="text-base-content/60">{description}</p>
				)}
			</div>
		</Link>
	)
}
