'use client'

import { useState, useEffect, useMemo } from 'react'
import type { z } from 'zod'
import type { Form } from '@growth-engine/types'
import { sdkFetch } from '../client'
import { buildFormSchema } from '../lib/buildFormSchema'

interface UseFormsResult {
  forms: Form[]
  loading: boolean
  error: string | null
}

interface UseFormResult {
  form: Form | null
  schema: z.ZodObject<Record<string, z.ZodTypeAny>> | null
  loading: boolean
  error: string | null
}

export function useForms(): UseFormsResult {
  const [forms, setForms] = useState<Form[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<Form[]>('/forms?action=list')
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setForms(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [])

  return { forms, loading, error }
}

export function useForm(slug: string): UseFormResult {
  const [form, setForm] = useState<Form | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<Form | null>(
        `/forms?action=get&slug=${encodeURIComponent(slug)}`,
      )
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setForm(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [slug])

  const schema = useMemo(() => {
    if (!form?.fields) return null
    return buildFormSchema(form.fields)
  }, [form])

  return { form, schema, loading, error }
}

export async function submitForm(
  slug: string,
  data: Record<string, unknown>,
): Promise<{ ok: boolean, id?: string, error?: string, validationErrors?: z.ZodIssue[] }> {
  // Fetch form definition to validate against
  const formRes = await sdkFetch<Form | null>(
    `/forms?action=get&slug=${encodeURIComponent(slug)}`,
  )

  if (formRes.error || !formRes.data) {
    return { ok: false, error: formRes.error ?? 'Form not found' }
  }

  // Build and validate against schema
  const schema = buildFormSchema(formRes.data.fields)
  const result = schema.safeParse(data)
  if (!result.success) {
    return { ok: false, error: 'Validation failed', validationErrors: result.error.issues }
  }

  const res = await sdkFetch<{ ok: boolean, id?: string, error?: string }>(
    `/forms?action=submit&slug=${encodeURIComponent(slug)}`,
    {
      method: 'POST',
      body: JSON.stringify({ data }),
    },
  )
  if (res.error) {
    return { ok: false, error: res.error }
  }
  return res.data
}
