'use client'

import { useState, useMemo } from 'react'
import { BlogCard } from './BlogCard'
import { BlogSearch } from './BlogSearch'
import type { BlogCardProps } from './BlogCard'

export interface BlogListTranslations {
	noPostsMessage: string
	clearSearchLabel: string
	searchPlaceholder: string
}

export interface BlogListProps {
	posts: BlogCardProps[]
	locale: string
	translations: BlogListTranslations
}

const POSTS_PER_PAGE = 9

export function BlogList({ posts, locale, translations }: BlogListProps) {
	const [search, setSearch] = useState('')
	const [page, setPage] = useState(1)

	const filtered = useMemo(() => {
		if (!search.trim()) return posts
		const q = search.toLowerCase()
		return posts.filter(
			(p) =>
				p.title.toLowerCase().includes(q) ||
				(p.seoDesc && p.seoDesc.toLowerCase().includes(q)),
		)
	}, [posts, search])

	const totalPages = Math.ceil(filtered.length / POSTS_PER_PAGE)
	const paginated = filtered.slice((page - 1) * POSTS_PER_PAGE, page * POSTS_PER_PAGE)

	return (
		<section aria-label="Blog posts">
			<BlogSearch
				value={search}
				onChange={(v) => { setSearch(v); setPage(1) }}
				placeholder={translations.searchPlaceholder}
			/>

			{paginated.length === 0 ? (
				<div className="text-center py-16 text-base-content/50">
					<p className="text-lg">{translations.noPostsMessage}</p>
					{search && (
						<button
							onClick={() => setSearch('')}
							className="btn btn-ghost btn-sm mt-2"
						>
							{translations.clearSearchLabel}
						</button>
					)}
				</div>
			) : (
				<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
					{paginated.map((post) => (
						<BlogCard
							key={post.slug}
							{...post}
							locale={locale}
						/>
					))}
				</div>
			)}

			{totalPages > 1 && (
				<div className="flex justify-center mt-8">
					<nav aria-label="Blog pagination" className="join">
						<button
							className="join-item btn btn-sm"
							disabled={page <= 1}
							onClick={() => setPage(page - 1)}
							aria-label="Previous page"
						>
							&laquo;
						</button>
						{Array.from({ length: totalPages }, (_, i) => i + 1).map((p) => (
							<button
								key={p}
								className={`join-item btn btn-sm ${p === page ? 'btn-active' : ''}`}
								onClick={() => setPage(p)}
								aria-label={`Page ${p}`}
								aria-current={p === page ? 'page' : undefined}
							>
								{p}
							</button>
						))}
						<button
							className="join-item btn btn-sm"
							disabled={page >= totalPages}
							onClick={() => setPage(page + 1)}
							aria-label="Next page"
						>
							&raquo;
						</button>
					</nav>
				</div>
			)}
		</section>
	)
}
