import type { BusinessConfig } from '@growth-engine/types'
import { buildLocalBusinessLd } from './json-ld'
import { JsonLd } from './JsonLd'

export function BusinessJsonLd({ config }: { config: BusinessConfig }) {
	const ld = buildLocalBusinessLd(config)
	if (!ld) return null
	return <JsonLd data={ld} />
}
