import Link from 'next/link'

export interface BlogCardProps {
	slug: string
	title: string
	content: string
	heroImageUrl: string | null
	seoDesc: string | null
	createdAt: Date | string
	locale: string
}

function formatDate(date: Date | string, locale: string): string {
	return new Date(date).toLocaleDateString(locale, {
		year: 'numeric',
		month: 'long',
		day: 'numeric',
	})
}

export function BlogCard({ slug, title, content, heroImageUrl, seoDesc, createdAt, locale }: BlogCardProps) {
	const date = formatDate(createdAt, locale)
	const isoDate = new Date(createdAt).toISOString()
	const preview = seoDesc ?? content.replace(/<[^>]*>/g, '').slice(0, 160) + '...'

	return (
		<article itemScope itemType="https://schema.org/BlogPosting">
			<Link href={`/${locale}/blog/${slug}`} className="card bg-base-100 shadow-sm border border-base-200 hover:shadow-md transition-shadow group">
				{heroImageUrl && (
					<figure className="aspect-video overflow-hidden">
						<img
							src={heroImageUrl}
							alt={title}
							className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
						/>
					</figure>
				)}
				<div className="card-body">
					<time className="text-xs text-base-content/50" dateTime={isoDate}>{date}</time>
					<h2 className="card-title text-lg group-hover:text-primary transition-colors">{title}</h2>
					<p className="text-sm text-base-content/70 line-clamp-3">{preview}</p>
				</div>
			</Link>
		</article>
	)
}
