'use client'

import { useState, useEffect } from 'react'
import type { Form } from '@growth-engine/types'
import { submitForm } from '../../hooks/useForms'

export interface FormRendererTranslations {
	submittingLabel?: string | undefined
	defaultSubmitLabel?: string | undefined
	defaultSuccessMessage?: string | undefined
}

export interface FormRendererProps {
	form: Form
	translations?: FormRendererTranslations | undefined
	onSubmitSuccess?: ((id: string) => void) | undefined
}

export function FormRenderer({ form, translations, onSubmitSuccess }: FormRendererProps) {
	const [formData, setFormData] = useState<Record<string, unknown>>({})
	const [submitting, setSubmitting] = useState(false)
	const [submitted, setSubmitted] = useState(false)
	const [error, setError] = useState('')
	const [initialized, setInitialized] = useState(false)

	useEffect(() => {
		if (initialized) return
		const initial: Record<string, unknown> = {}
		for (const field of form.fields) {
			if (field.type === 'checkbox') {
				initial[field.name] = false
			} else {
				initial[field.name] = ''
			}
		}
		setFormData(initial)
		setInitialized(true)
	}, [form.fields, initialized])

	function updateField(name: string, value: unknown) {
		setFormData((prev) => ({ ...prev, [name]: value }))
	}

	async function handleSubmit(e: React.FormEvent) {
		e.preventDefault()
		setError('')
		setSubmitting(true)

		try {
			const result = await submitForm(form.slug, formData)
			if (!result.ok) {
				if (result.validationErrors) {
					setError(result.validationErrors.map((ve) => ve.message).join(', '))
				} else {
					setError(result.error ?? 'Something went wrong')
				}
				return
			}
			setSubmitted(true)
			if (result.id && onSubmitSuccess) {
				onSubmitSuccess(result.id)
			}
		} catch {
			setError('Failed to submit. Please try again.')
		} finally {
			setSubmitting(false)
		}
	}

	if (submitted) {
		const settings = typeof form.settings === 'string'
			? JSON.parse(form.settings) as { successMessage?: string }
			: form.settings

		return (
			<div className="mx-auto max-w-lg rounded-xl border bg-base-100 p-8 text-center shadow-lg">
				<div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-success/20">
					<svg className="h-6 w-6 text-success" fill="none" viewBox="0 0 24 24" stroke="currentColor">
						<path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
					</svg>
				</div>
				<h2 className="text-xl font-semibold">
					{settings?.successMessage ?? translations?.defaultSuccessMessage ?? 'Thank you for your submission!'}
				</h2>
			</div>
		)
	}

	const sortedFields = [...form.fields].sort((a, b) => a.order - b.order)
	const settings = typeof form.settings === 'string'
		? JSON.parse(form.settings) as { submitButtonText?: string }
		: form.settings

	return (
		<div className="mx-auto max-w-lg">
			<h1 className="text-3xl font-bold">{form.name}</h1>
			{form.description && (
				<p className="mt-2 text-base-content/60">{form.description}</p>
			)}

			<form onSubmit={handleSubmit} className="mt-8 space-y-4">
				{sortedFields.map((field) => (
					<div key={field.name} className="form-control w-full">
						<label htmlFor={field.name} className="label">
							<span className="label-text">
								{field.label}
								{field.required && <span className="ml-1 text-error">*</span>}
							</span>
						</label>

						{field.type === 'textarea' ? (
							<textarea
								id={field.name}
								required={field.required}
								placeholder={field.placeholder}
								rows={4}
								value={String(formData[field.name] ?? '')}
								onChange={(e) => updateField(field.name, e.target.value)}
								className="textarea textarea-bordered w-full"
							/>
						) : field.type === 'select' ? (
							<select
								id={field.name}
								required={field.required}
								value={String(formData[field.name] ?? '')}
								onChange={(e) => updateField(field.name, e.target.value)}
								className="select select-bordered w-full"
							>
								<option value="">{field.placeholder ?? 'Select...'}</option>
								{(field.options ?? []).map((opt) => (
									<option key={opt} value={opt}>{opt}</option>
								))}
							</select>
						) : field.type === 'checkbox' ? (
							<label className="label cursor-pointer justify-start gap-3">
								<input
									type="checkbox"
									id={field.name}
									required={field.required}
									checked={Boolean(formData[field.name])}
									onChange={(e) => updateField(field.name, e.target.checked)}
									className="checkbox"
								/>
								<span className="label-text">{field.placeholder}</span>
							</label>
						) : (
							<input
								type={field.type}
								id={field.name}
								required={field.required}
								placeholder={field.placeholder}
								value={String(formData[field.name] ?? '')}
								onChange={(e) => updateField(field.name, e.target.value)}
								className="input input-bordered w-full"
							/>
						)}
					</div>
				))}

				{error && (
					<div className="alert alert-error">
						<span>{error}</span>
					</div>
				)}

				<button
					type="submit"
					disabled={submitting}
					className="btn btn-primary w-full"
				>
					{submitting
						? (translations?.submittingLabel ?? 'Submitting...')
						: (settings?.submitButtonText ?? translations?.defaultSubmitLabel ?? 'Submit')}
				</button>
			</form>
		</div>
	)
}
