import { marked } from 'marked'
import type { BlogPost, BlogAuthor, BusinessConfig } from '@growth-engine/types'
import { buildBlogPostingLd } from '../../seo/json-ld'
import { JsonLd } from '../../seo/JsonLd'
import { MetaTags } from '../../seo/MetaTags'

export interface BlogContentProps {
	html: string
	post?: BlogPost
	author?: BlogAuthor
	business?: BusinessConfig
	disableMeta?: boolean
	disableJsonLd?: boolean
}

export function BlogContent({
	html,
	post,
	author,
	business,
	disableMeta,
	disableJsonLd,
}: BlogContentProps) {
	const jsonLd = post && !disableJsonLd
		? buildBlogPostingLd(post, author, business)
		: null

	return (
		<article itemScope itemType="https://schema.org/BlogPosting">
			{jsonLd && <JsonLd data={jsonLd} />}
			{post && !disableMeta && (
				<MetaTags
					title={post.seoTitle ?? post.title}
					description={post.seoDesc}
					image={post.heroImageUrl}
					type="article"
				/>
			)}
			<div
				className="prose prose-lg max-w-none"
				dangerouslySetInnerHTML={{ __html: marked.parse(html, { async: false }) as string }}
			/>
		</article>
	)
}
