import type { BlogPost, BlogAuthor, BusinessConfig } from '@growth-engine/types'

type JsonLdObject = Record<string, unknown>

function omitNulls(obj: Record<string, unknown>): Record<string, unknown> {
	const result: Record<string, unknown> = {}
	for (const [key, value] of Object.entries(obj)) {
		if (value != null) {
			result[key] = value
		}
	}
	return result
}

export function buildBlogPostingLd(
	post: BlogPost,
	author?: BlogAuthor,
	business?: BusinessConfig,
): JsonLdObject {
	const ld: JsonLdObject = {
		'@context': 'https://schema.org',
		'@type': 'BlogPosting',
		...omitNulls({
			headline: post.seoTitle ?? post.title,
			description: post.seoDesc,
			image: post.heroImageUrl,
			datePublished: post.publishedAt ? new Date(post.publishedAt).toISOString() : null,
			dateModified: new Date(post.updatedAt).toISOString(),
			inLanguage: post.language,
		}),
	}

	if (author) {
		ld.author = omitNulls({
			'@type': 'Person',
			name: author.name,
			url: author.websiteUrl,
			image: author.avatarUrl,
		})
	}

	if (business?.name) {
		ld.publisher = omitNulls({
			'@type': 'Organization',
			name: business.name,
			url: business.website,
		})
	}

	return ld
}

export function buildLocalBusinessLd(
	config: BusinessConfig,
): JsonLdObject | null {
	if (!config.name) return null

	const ld: JsonLdObject = {
		'@context': 'https://schema.org',
		'@type': 'LocalBusiness',
		...omitNulls({
			name: config.name,
			description: config.description,
			telephone: config.phone,
			email: config.email,
			url: config.website,
		}),
	}

	if (config.address && typeof config.address === 'object') {
		ld.address = {
			'@type': 'PostalAddress',
			...config.address,
		}
	}

	return ld
}
